const ATHLETE_ID = 372001;
const ZONE_BANDS = [
  ['z1', 0.50, 0.59],
  ['z2', 0.60, 0.69],
  ['z3', 0.70, 0.79],
  ['z4', 0.80, 0.89],
  ['z5', 0.90, 1.00],
];

const isObject = (value) => value !== null && typeof value === 'object' && !Array.isArray(value);

const toNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const getNodeItemsSafe = (nodeName) => {
  try {
    const nodeItems = $items(nodeName);
    return Array.isArray(nodeItems) ? nodeItems : [];
  } catch {
    return [];
  }
};

const getByPath = (obj, path) => {
  if (!isObject(obj)) return undefined;
  const parts = path.split('.');
  let cursor = obj;
  for (const part of parts) {
    if (!isObject(cursor) || !Object.prototype.hasOwnProperty.call(cursor, part)) {
      return undefined;
    }
    cursor = cursor[part];
  }
  return cursor;
};

const pickNumber = (obj, paths) => {
  for (const path of paths) {
    const value = toNumber(getByPath(obj, path));
    if (value !== null) return value;
  }
  return null;
};

const normalizeZones = (raw) => {
  if (!isObject(raw)) return null;
  const keys = ['z1', 'z2', 'z3', 'z4', 'z5'];
  const normalized = {};

  for (const key of keys) {
    const zone = raw[key];
    if (!isObject(zone)) return null;
    const min = toNumber(zone.min);
    const max = toNumber(zone.max);
    if (min === null || max === null || min > max) return null;
    normalized[key] = { min: Math.round(min), max: Math.round(max) };
  }

  return normalized;
};

const computeHrrZones = (hrMax, hrRest) => {
  const reserve = hrMax - hrRest;
  const zones = {};
  for (const [key, lowPct, highPct] of ZONE_BANDS) {
    zones[key] = {
      min: Math.round(hrRest + reserve * lowPct),
      max: Math.round(hrRest + reserve * highPct),
    };
  }
  return zones;
};

const hasRunType = (types) => Array.isArray(types)
  && types.some((type) => typeof type === 'string' && /run/i.test(type));

const pickRunSport = (payload) => {
  if (!isObject(payload) || !Array.isArray(payload.sportSettings)) return null;
  return payload.sportSettings.find((entry) => isObject(entry) && hasRunType(entry.types)) || null;
};

const expandPayload = (value) => {
  if (Array.isArray(value)) {
    return value.filter((entry) => isObject(entry));
  }
  if (isObject(value)) {
    return [value];
  }
  return [];
};

const pickLatestWellnessRestingHr = (payloads) => {
  let best = null;
  let bestScore = -Infinity;

  for (const payload of payloads) {
    const wellnessRows = Array.isArray(payload.wellness) ? payload.wellness : [];
    for (let index = 0; index < wellnessRows.length; index += 1) {
      const row = wellnessRows[index];
      if (!isObject(row)) continue;
      const resting = toNumber(row.restingHR ?? row.restingHr ?? row.resting_hr);
      if (resting === null) continue;

      const tsCandidates = [row.id, row.date, row.updatedAt, row.updated]
        .filter((value) => typeof value === 'string' && value.trim());
      let score = -Infinity;
      for (const value of tsCandidates) {
        const parsed = Date.parse(value);
        if (Number.isFinite(parsed)) {
          score = Math.max(score, parsed);
        }
      }
      if (!Number.isFinite(score)) {
        score = index;
      }

      if (score >= bestScore) {
        bestScore = score;
        best = resting;
      }
    }
  }

  return best;
};

const eq = (a, b) => (a === null && b === null) || a === b;
const fmt = (value) => (value === null ? '-' : String(Math.round(value)));

const incomingPayloads = items
  .map((item) => (item && item.json ? item.json : null))
  .flatMap((payload) => expandPayload(payload));

const hrNodePayloads = getNodeItemsSafe('GET HR Parameters')
  .map((item) => (item && item.json ? item.json : null))
  .flatMap((payload) => expandPayload(payload));

const sourcePayloads = [...hrNodePayloads, ...incomingPayloads];

const mergedPayload = {};
for (const payload of incomingPayloads) {
  for (const [key, value] of Object.entries(payload)) {
    if (Array.isArray(value)) {
      if (!Array.isArray(mergedPayload[key]) || value.length > mergedPayload[key].length) {
        mergedPayload[key] = value;
      }
      continue;
    }
    if (isObject(value)) {
      if (!isObject(mergedPayload[key])) {
        mergedPayload[key] = {};
      }
      for (const [subKey, subValue] of Object.entries(value)) {
        if (!(subKey in mergedPayload[key]) || mergedPayload[key][subKey] === null || mergedPayload[key][subKey] === '') {
          mergedPayload[key][subKey] = subValue;
        }
      }
      continue;
    }
    if (!(key in mergedPayload) || mergedPayload[key] === null || mergedPayload[key] === '') {
      mergedPayload[key] = value;
    }
  }
}

const previousPayload = getNodeItemsSafe('Read Last HR Profile')
  .map((item) => (item && item.json && isObject(item.json) ? item.json : null))
  .find((payload) => payload !== null) || {};

const previous = {
  hrMax: toNumber(previousPayload.hrMax),
  hrRest: toNumber(previousPayload.hrRest),
  lthr: toNumber(previousPayload.lthr),
  zoneMethod: typeof previousPayload.zoneMethod === 'string' ? previousPayload.zoneMethod : null,
  computedZones: normalizeZones(previousPayload.computedZones),
};

const runSport = sourcePayloads
  .map((payload) => pickRunSport(payload))
  .find((sport) => sport !== null) || null;

const sourceHrMax = toNumber(runSport && runSport.max_hr);
const sourceLthr = toNumber(runSport && runSport.lthr);

const sourceHrRestFromAthlete = sourcePayloads
  .map((payload) => pickNumber(payload, ['icu_resting_hr', 'hrRest', 'restingHR', 'restingHr', 'resting_hr']))
  .find((value) => value !== null) || null;

const sourceHrRestFromWellness = pickLatestWellnessRestingHr(sourcePayloads);
const sourceHrRest = sourceHrRestFromAthlete !== null ? sourceHrRestFromAthlete : sourceHrRestFromWellness;

const validationErrors = [];
if (sourceHrMax === null) validationErrors.push('missing_hr_max');
if (sourceHrRest === null) validationErrors.push('missing_hr_rest');
if (sourceLthr === null) validationErrors.push('missing_lthr');
if (sourceHrMax !== null && sourceHrRest !== null && sourceHrRest >= sourceHrMax) {
  validationErrors.push('invalid_hr_rest_gte_hr_max');
}
if (sourceHrMax !== null && sourceLthr !== null && sourceHrMax < sourceLthr) {
  validationErrors.push('invalid_hr_max_lt_lthr');
}

const sourceIsValid = validationErrors.length === 0;

let nextHrMax = previous.hrMax;
let nextHrRest = previous.hrRest;
let nextLthr = previous.lthr;
let nextZoneMethod = previous.zoneMethod;
let nextComputedZones = previous.computedZones;

if (sourceIsValid) {
  nextHrMax = sourceHrMax;
  nextHrRest = sourceHrRest;
  nextLthr = sourceLthr;
  nextZoneMethod = '%HRR';
  nextComputedZones = computeHrrZones(sourceHrMax, sourceHrRest);
}

const hasValidProfile = Number.isFinite(nextHrMax)
  && Number.isFinite(nextHrRest)
  && nextHrRest < nextHrMax
  && (nextLthr === null || (Number.isFinite(nextLthr) && nextHrMax >= nextLthr))
  && normalizeZones(nextComputedZones) !== null;

const inputsChanged = sourceIsValid && (
  !eq(previous.hrMax, sourceHrMax)
  || !eq(previous.hrRest, sourceHrRest)
  || !eq(previous.lthr, sourceLthr)
);

const zonesUpdated = hasValidProfile && inputsChanged;
const persistProfile = hasValidProfile && inputsChanged;
const nowIso = new Date().toISOString();

const incomingRunId = typeof mergedPayload.runId === 'string' && mergedPayload.runId.trim()
  ? mergedPayload.runId.trim()
  : null;
const runId = incomingRunId || `${nowIso}-${Math.random().toString(36).slice(2, 8)}`;

const zoneUpdateNotice = zonesUpdated
  ? `🛠️ Zonas actualizadas: Max ${fmt(previous.hrMax)}→${fmt(nextHrMax)} · Reposo ${fmt(previous.hrRest)}→${fmt(nextHrRest)} · Umbral ${fmt(previous.lthr)}→${fmt(nextLthr)}`
  : null;

const hrSyncLog = {
  run_id: runId,
  hrMax_old: previous.hrMax,
  hrMax_new: nextHrMax,
  hrRest_old: previous.hrRest,
  hrRest_new: nextHrRest,
  lthr_old: previous.lthr,
  lthr_new: nextLthr,
  zonesUpdated,
  validationErrors,
  updatedAt: nowIso,
};

const heartRateSync = {
  athleteId: ATHLETE_ID,
  hrMax: nextHrMax,
  hrRest: nextHrRest,
  lthr: nextLthr,
  zoneMethod: nextZoneMethod,
  computedZones: nextComputedZones,
  updatedAt: nowIso,
  zonesUpdated,
  zoneUpdateNotice,
  persistProfile,
  validationErrors,
  hrSyncLog,
};

return [{
  json: Object.assign({}, mergedPayload, {
    runId,
    heartRateSync,
    heartRate: heartRateSync,
    hrSyncLog,
    athleteId: ATHLETE_ID,
    hrMax: nextHrMax,
    hrRest: nextHrRest,
    lthr: nextLthr,
    zoneMethod: nextZoneMethod,
    computedZones: nextComputedZones,
    updatedAt: nowIso,
    zonesUpdated,
    zoneUpdateNotice,
    persistProfile,
  }),
}];
